import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedCode {

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        if (userInput != null) {
            userInput = sanitizeInput(userInput); // Sanitize user input
        } else {
            userInput = "Guest"; // Default value if input is empty
        }

        String message = "Welcome, " + userInput + "!";

        response.getWriter().println("<html><body>");
        response.getWriter().println("<h1>" + message + "</h1>");
        response.getWriter().println("</body></html>");
    }

    private String sanitizeInput(String input) {
        // Replace characters that may be interpreted as HTML tags with their HTML entity equivalents
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("&", "&amp;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
